1	"use client";
2	
3	import { useState, useCallback, useRef } from "react";
4	import { useTranslations, useLocale } from "next-intl";
5	import { useRouter } from "@/i18n/navigation";
6	import { Button } from "@/shared/components/ui/Button";
7	import { Input } from "@/shared/components/ui/Input";
8	import { Textarea } from "@/shared/components/ui/Textarea";
9	import { Select } from "@/shared/components/ui/Select";
10	import { Card } from "@/shared/components/ui/Card";
11	import { useToast } from "@/shared/components/ui/Toaster";
12	import {
13	  createQuoteAction,
14	  updateQuoteAction,
15	} from "../actions";
16	import type { Quote, LineItem, Currency, Deliverable, QuoteType } from "../types";
17	import {
18	  CURRENCY_LABELS,
19	  formatCurrency,
20	  calculateLineItemTotal,
21	  calculateSubtotal,
22	  calculateTotal,
23	} from "../types";
24	import { nanoid } from "nanoid";
25	import { Plus, X, Save, Link2, Eye } from "lucide-react";
26	
27	interface QuoteFormProps {
28	  quote?: Quote;
29	}
30	
31	type FieldErrors = Record<string, string[] | undefined>;
32	
33	export function QuoteForm({ quote }: QuoteFormProps) {
34	  const t = useTranslations("Admin");
35	  const locale = useLocale();
36	  const router = useRouter();
37	  const { toast } = useToast();
38	  const formRef = useRef<HTMLFormElement>(null);
39	
40	  const [quoteType, setQuoteType] = useState<QuoteType>(
41	    quote?.quoteType || "line-items"
42	  );
43	  const [lineItems, setLineItems] = useState<LineItem[]>(
44	    quote?.lineItems?.length
45	      ? quote.lineItems
46	      : [{ id: nanoid(6), description: "", quantity: 1, unitPrice: 0 }]
47	  );
48	  const [currency, setCurrency] = useState<Currency>(
49	    quote?.currency || "MXN"
50	  );
51	  const [discount, setDiscount] = useState(quote?.discount || 0);
52	  const [deliverables, setDeliverables] = useState<Deliverable[]>(
53	    quote?.deliverables || []
54	  );
55	  const [nextSteps, setNextSteps] = useState<string[]>(
56	    quote?.nextSteps || []
57	  );
58	  const [fieldErrors, setFieldErrors] = useState<FieldErrors>({});
59	  const [isSubmitting, setIsSubmitting] = useState(false);
60	
61	  // Line item handlers
62	  const addLineItem = useCallback(() => {
63	    setLineItems((prev) => [
64	      ...prev,
65	      { id: nanoid(6), description: "", quantity: 1, unitPrice: 0 },
66	    ]);
67	  }, []);
68	
69	  const removeLineItem = useCallback((id: string) => {
70	    setLineItems((prev) => prev.filter((item) => item.id !== id));
71	  }, []);
72	
73	  const updateLineItem = useCallback(
74	    (id: string, field: keyof LineItem, value: string | number) => {
75	      setLineItems((prev) =>
76	        prev.map((item) =>
77	          item.id === id ? { ...item, [field]: value } : item
78	        )
79	      );
80	    },
81	    []
82	  );
83	
84	  // Deliverable handlers
85	  const addDeliverable = useCallback(() => {
86	    setDeliverables((prev) => [
87	      ...prev,
88	      {
89	        id: nanoid(6),
90	        number: prev.length + 1,
91	        title: "",
92	        description: "",
93	      },
94	    ]);
95	  }, []);
96	
97	  const removeDeliverable = useCallback((id: string) => {
98	    setDeliverables((prev) => {
99	      const filtered = prev.filter((d) => d.id !== id);
100	      return filtered.map((d, i) => ({ ...d, number: i + 1 }));
101	    });
102	  }, []);
103	
104	  const updateDeliverable = useCallback(
105	    (id: string, field: keyof Deliverable, value: string | number) => {
106	      setDeliverables((prev) =>
107	        prev.map((d) => (d.id === id ? { ...d, [field]: value } : d))
108	      );
109	    },
110	    []
111	  );
112	
113	  // Next step handlers
114	  const addNextStep = useCallback(() => {
115	    setNextSteps((prev) => [...prev, ""]);
116	  }, []);
117	
118	  const removeNextStep = useCallback((index: number) => {
119	    setNextSteps((prev) => prev.filter((_, i) => i !== index));
120	  }, []);
121	
122	  const updateNextStep = useCallback((index: number, value: string) => {
123	    setNextSteps((prev) => prev.map((s, i) => (i === index ? value : s)));
124	  }, []);
125	
126	  const subtotal = calculateSubtotal(lineItems);
127	  const total = calculateTotal(lineItems, discount);
128	
129	  function buildFormData(base: FormData, status: string): FormData {
130	    base.set("quoteType", quoteType);
131	    base.set("currency", currency);
132	    base.set("status", status);
133	
134	    if (quoteType === "line-items") {
135	      base.set("lineItems", JSON.stringify(lineItems));
136	      base.set("discount", discount.toString());
137	    } else {
138	      base.set("lineItems", "[]");
139	      base.set("discount", "0");
140	      base.set("deliverables", JSON.stringify(deliverables));
141	      base.set("nextSteps", JSON.stringify(nextSteps));
142	    }
143	    return base;
144	  }
145	
146	  async function handleSubmit(formData: FormData, status: string) {
147	    setIsSubmitting(true);
148	    setFieldErrors({});
149	    buildFormData(formData, status);
150	
151	    if (quote) {
152	      const result = await updateQuoteAction(quote.id, formData);
153	      setIsSubmitting(false);
154	      if ("error" in result) {
155	        setFieldErrors(result.error as FieldErrors);
156	        toast("Please fix the errors below", "error");
157	        return;
158	      }
159	      toast("Quote saved", "success");
160	      router.push("/admin");
161	    } else {
162	      const result = await createQuoteAction(formData);
163	      setIsSubmitting(false);
164	      if ("error" in result) {
165	        setFieldErrors(result.error as FieldErrors);
166	        toast("Please fix the errors below", "error");
167	        return;
168	      }
169	
170	      if (status === "sent" && result.id) {
171	        const baseUrl = window.location.origin;
172	        await navigator.clipboard.writeText(
173	          `${baseUrl}/${locale}/quote/${result.id}`
174	        );
175	        toast("Link copied to clipboard!", "success");
176	        setTimeout(() => router.push("/admin"), 1500);
177	      } else {
178	        toast("Quote saved as draft", "success");
179	        router.push("/admin");
180	      }
181	    }
182	  }
183	
184	  async function handlePreview() {
185	    if (!formRef.current) return;
186	    const formData = buildFormData(new FormData(formRef.current), "draft");
187	
188	    if (quote) {
189	      // Already saved — just open in new tab
190	      window.open(`/${locale}/quote/${quote.id}`, "_blank");
191	      return;
192	    }
193	
194	    // New quote: save as draft first, then open preview
195	    setIsSubmitting(true);
196	    setFieldErrors({});
197	    const result = await createQuoteAction(formData);
198	    setIsSubmitting(false);
199	
200	    if ("error" in result) {
201	      setFieldErrors(result.error as FieldErrors);
202	      toast("Please fix the errors below", "error");
203	      return;
204	    }
205	
206	    window.open(`/${locale}/quote/${result.id}`, "_blank");
207	    toast("Draft saved — redirecting to edit", "info");
208	    router.push(`/admin/quotes/${result.id}/edit`);
209	  }
210	
211	  const currencyOptions = Object.entries(CURRENCY_LABELS).map(
212	    ([value, label]) => ({ value, label })
213	  );
214	
215	  return (
216	    <form
217	      ref={formRef}
218	      action={async (formData) => handleSubmit(formData, "draft")}
219	      className="max-w-4xl mx-auto space-y-6"
220	    >
221	      {/* Quote Type Toggle */}
222	      <Card>
223	        <h3 className="text-sm font-semibold text-pragma-muted uppercase tracking-wider mb-4">
224	          {t("quoteType")}
225	        </h3>
226	        <div className="flex gap-2">
227	          <button
228	            type="button"
229	            onClick={() => setQuoteType("line-items")}
