@import "tailwindcss";

@theme inline {
  --color-pragma-bg: #0a0a0f;
  --color-pragma-surface: #12121a;
  --color-pragma-border: #1e1e2e;
  --color-pragma-accent: #00f0ff;
  --color-pragma-accent-2: #7c3aed;
  --color-pragma-accent-3: #00ff88;
  --color-pragma-text: #e4e4e7;
  --color-pragma-muted: #71717a;

  --font-display: "Space Grotesk", system-ui, sans-serif;
  --font-sans: "Inter", system-ui, sans-serif;
  --font-mono: "JetBrains Mono", monospace;

  --animate-glow-pulse: glow-pulse 3s ease-in-out infinite;
  --animate-float: float 6s ease-in-out infinite;
  --animate-fade-in: fade-in 0.6s ease-out forwards;
  --animate-slide-up: slide-up 0.6s ease-out forwards;

  @keyframes glow-pulse {
    0%, 100% { opacity: 0.4; }
    50% { opacity: 1; }
  }

  @keyframes float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-10px); }
  }

  @keyframes fade-in {
    from { opacity: 0; }
    to { opacity: 1; }
  }

  @keyframes slide-up {
    from { opacity: 0; transform: translateY(30px); }
    to { opacity: 1; transform: translateY(0); }
  }
}

@layer base {
  body {
    background-color: var(--color-pragma-bg);
    color: var(--color-pragma-text);
    font-family: var(--font-sans);
  }
}

/* Dot grid background */
.bg-grid {
  background-image: radial-gradient(circle, rgba(255, 255, 255, 0.03) 1px, transparent 1px);
  background-size: 30px 30px;
}

/* Gradient mesh for hero */
.bg-gradient-mesh {
  background:
    radial-gradient(ellipse at 20% 50%, rgba(0, 240, 255, 0.08) 0%, transparent 50%),
    radial-gradient(ellipse at 80% 20%, rgba(124, 58, 237, 0.08) 0%, transparent 50%),
    radial-gradient(ellipse at 50% 80%, rgba(0, 255, 136, 0.05) 0%, transparent 50%);
}

/* Glow effects */
.glow-cyan {
  box-shadow: 0 0 20px rgba(0, 240, 255, 0.3);
}

.glow-purple {
  box-shadow: 0 0 20px rgba(124, 58, 237, 0.3);
}

.glow-green {
  box-shadow: 0 0 20px rgba(0, 255, 136, 0.3);
}

/* Scrollbar styling */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: var(--color-pragma-bg);
}

::-webkit-scrollbar-thumb {
  background: var(--color-pragma-border);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--color-pragma-muted);
}

