            {quote.title}
          </h1>
          <div className="flex flex-wrap gap-3 mt-2 text-sm text-pragma-muted">
            <span>
              {t("quoteNumber")} #{quote.id}
            </span>
            <span>&middot;</span>
            <span>
              {t("date")}:{" "}
              {new Date(quote.createdAt).toLocaleDateString(dateFormatLocale)}
