    keywords: [
      "AI consulting",
      "custom AI solutions",
      "machine learning",
      "web development",
      "process automation",
      "Mexico City",
      "PRAGMA",
    ],
    ogLocale: "en_US",
    ogAltLocale: "es_MX",
  },
  es: {
    title: "PRAGMA | Soluciones de IA y Tecnología",
    description:
      "Soluciones de IA pragmáticas para impacto real. Sistemas de IA personalizados, desarrollo web, automatización de procesos y consultoría para empresas.",
    keywords: [
      "consultoría IA",
      "soluciones de inteligencia artificial",
      "machine learning",
      "desarrollo web",
      "automatización",
      "Ciudad de México",
      "PRAGMA",
    ],
    ogLocale: "es_MX",
    ogAltLocale: "en_US",
  },
};

type Props = { params: Promise<{ locale: string }> };

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { locale } = await params;
  const meta = META[locale as keyof typeof META] ?? META.en;
  const url = `${BASE_URL}/${locale}`;

  return {
    title: meta.title,
    description: meta.description,
    keywords: meta.keywords,
    authors: [{ name: "PRAGMA" }],
    metadataBase: new URL(BASE_URL),
    alternates: {
      canonical: url,
      languages: {
        en: `${BASE_URL}/en`,
        es: `${BASE_URL}/es`,
      },
    },
    openGraph: {
      type: "website",
      locale: meta.ogLocale,
      alternateLocale: meta.ogAltLocale,
      url,
      siteName: "PRAGMA",
      title: meta.title,
      description: meta.description,
    },
    twitter: {
      card: "summary_large_image",
      title: meta.title,
      description: meta.description,
    },
  };
}

