    address: {
      "@type": "PostalAddress",
      addressLocality: "Mexico City",
      addressCountry: "MX",
    },
    sameAs: [],
  };

  const servicesSchema = {
    "@context": "https://schema.org",
    "@type": "WebSite",
    name: "PRAGMA",
    url: `${BASE_URL}/${locale}`,
    potentialAction: {
      "@type": "SearchAction",
      target: `${BASE_URL}/${locale}#contact`,
    },
  };

  return (
    <>
      <JsonLd data={orgSchema} />
      <JsonLd data={servicesSchema} />
      <Navbar />
      <main>
        <Hero />
        <Services />
        <About />
        <CaseStudies />
        <Testimonials />
        <Contact />
      </main>
      <Footer />
    </>
  );
}

