1	export type QuoteType = "line-items" | "blueprint";
2	
3	export interface Deliverable {
4	  id: string;
5	  number: number;
6	  title: string;
7	  description: string;
8	}
9	
10	export interface LineItem {
11	  id: string;
12	  description: string;
13	  quantity: number;
14	  unitPrice: number;
15	}
16	
17	export type Currency = "USD" | "EUR" | "MXN" | "COP";
18	export type QuoteStatus = "draft" | "sent" | "accepted" | "rejected";
19	export type QuoteLocale = "en" | "es";
20	
21	export interface Quote {
22	  id: string;
23	  clientName: string;
24	  clientEmail: string;
25	  clientCompany: string;
26	  title: string;
27	  description: string;
28	  quoteType: QuoteType;
29	  lineItems: LineItem[];
30	  currency: Currency;
31	  discount: number;
32	  notes: string;
33	  status: QuoteStatus;
34	  validUntil: string;
35	  locale: QuoteLocale;
36	  createdAt: string;
37	  updatedAt: string;
38	  // Blueprint-only fields
39	  problem?: string;
40	  opportunity?: string;
41	  deliverables?: Deliverable[];
42	  timeline?: string;
43	  fixedPrice?: number;
44	  listPrice?: number;
45	  preferentialNote?: string;
46	  paymentTerms?: string;
47	  nextSteps?: string[];
48	  scopeNote?: string;
49	}
50	
51	export const CURRENCY_SYMBOLS: Record<Currency, string> = {
52	  USD: "$",
53	  EUR: "\u20AC",
54	  MXN: "$",
55	  COP: "$",
56	};
57	
58	export const CURRENCY_LABELS: Record<Currency, string> = {
59	  USD: "USD ($)",
60	  EUR: "EUR (\u20AC)",
61	  MXN: "MXN ($)",
62	  COP: "COP ($)",
63	};
64	
65	export function formatCurrency(
66	  amount: number,
67	  currency: Currency,
68	  locale: string = "en"
69	): string {
70	  return new Intl.NumberFormat(locale === "es" ? "es-MX" : "en-US", {
71	    style: "currency",
72	    currency,
73	    minimumFractionDigits: 2,
74	  }).format(amount);
75	}
76	
77	export function calculateLineItemTotal(item: LineItem): number {
78	  return item.quantity * item.unitPrice;
79	}
80	
81	export function calculateSubtotal(items: LineItem[]): number {
82	  return items.reduce((sum, item) => sum + calculateLineItemTotal(item), 0);
83	}
84	
85	export function calculateTotal(items: LineItem[], discount: number): number {
86	  const subtotal = calculateSubtotal(items);
87	  return subtotal - subtotal * (discount / 100);
88	}
