  const ip =
    hdrs.get("x-forwarded-for")?.split(",")[0]?.trim() ??
    hdrs.get("x-real-ip") ??
    "unknown";

  const limit = rateLimit(`pdf:${ip}`, { limit: 30, windowMs: 60 * 1000 });
